/bin/zsh -lc "node <<'NODE'
const assert = require('assert');
const { parseFrontMatter } = require('./src/markdown/frontmatter');
assert.deepStrictEqual(parseFrontMatter('hello\\n---\\ntitle: nope'), { metadata: {}, body: 'hello\\n---\\ntitle: nope' });
assert.deepStrictEqual(parseFrontMatter('---\\ntitle: yes\\n---\\nbody'), { metadata: { title: 'yes' }, body: 'body' });
assert.deepStrictEqual(parseFrontMatter('---\\r\\ntitle: yes\\r\\n---\\r\\nbody'), { metadata: { title: 'yes' }, body: 'body' });
assert.deepStrictEqual(parseFrontMatter('---\\ntitle: nope'), { metadata: {}, body: '---\\ntitle: nope' });
NODE"
